  ('judicial-57f41407-moex-00833', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列承辦法官，何者應自行迴避？', '["事件經調解不成立而進入訴訟程序者，曾參與該事件調解程序之法官", "下級審之判決經上級審廢棄而發回更審者，曾參與該更審前判決之法官", "曾參與該事件保全程序之法官", "上訴至最高法院之事件，曾參與該事件第二審判決之法官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00834', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者非專屬管轄事件？', '["基於買賣契約請求移轉土地所有權之訴", "請求裁判分割共有土地之訴", "確認四層樓房屋所有權之訴", "基於物上請求權請求拆屋還地之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00835', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', 'A起訴請求B給付貨款新臺幣（下同）90萬元，於訴訟進行中，C提起主參加訴訟，主張：A前已將 該貨款債權讓與C，請求B應給付90萬元貨款與C。下列敘述何者錯誤？', '["C提起主參加訴訟之被告應為A", "法院如駁回主參加訴訟，主參加訴訟之訴訟費用應由C負擔", "主參加訴訟原則上應與本訴訟合併辯論、裁判", "不論本訴訟在第一審或第二審，C均得提起主參加訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00836', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '受輔助宣告人所為何種行為無須經輔助人同意？', '["就訴訟標的為認諾", "撤回起訴", "就他造之上訴為答辯", "與他造和解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00837', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲係乙之債權人，得知乙與丙成立贈與契約以脫產規避債權，甲遂依民法第244條之規定，提起撤銷 贈與契約之訴。下列敘述何者正確？', '["丙如果對甲為訴訟標的之認諾，其認諾不生效力", "甲如果單獨對丙撤回起訴，其撤回僅對丙發生效力", "如果訴訟過程中，乙抗辯其所為贈與對甲之債權不生損害，此防禦方法僅對乙發生效力", "法院判決甲勝訴而撤銷乙、丙間之贈與契約，丙捨棄上訴，僅乙提起上訴，第二審之審理範圍僅限 於甲對乙的訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00838', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何項聲請，免徵裁判費或聲請費？', '["聲請駁回訴訟參加", "就標的為新臺幣5萬元之財產權事件聲請調解", "就確定裁定聲請再審", "聲請回復原狀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00839', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者非民事訴訟法所定之送達機關？', '["法院、法院書記官", "執達員、郵務人員", "對於有治外法權之人為送達時，受囑託送達之外交部", "對於緊急應為送達時，受囑託送達之物流快遞機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00840', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟程序之當事人書狀，下列敘述何者正確？', '["當事人或代理人應於書狀內簽名或蓋章。其以指印代簽名者，應由他人代書姓名，記明其事由並簽名", "已委任訴訟代理人之當事人，應於書狀內附委任狀並應載明已給付之律師酬金，以利計算訴訟費用", "原告提出之起訴狀不合程式者，審判長應定20日不變期間令其補正，逾期未補正者，逕以起訴不 合程式，裁定駁回之", "被告提出之答辯狀不合程式者，審判長應定20日不變期間令其補正，逾期未補正者，視同未提出 答辯狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00841', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於審判長之闡明權與當事人之發問權，下列敘述何者正確？', '["依原告之聲明，得主張數項法律關係，而其主張不完足者，審判長應命原告於7日內以書面補足之", "當事人得聲請審判長向他造為必要之發問，然當事人已委任訴訟代理人者，應由訴訟代理人聲請發問", "當事人如認為審判長關於訴訟指揮有不當者，得向上級法院提出抗告", "審判長認為當事人聲請之發問有不當者，得不為發問"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00842', 'judicial-57f41407', 'judicial-57f41407-moex-110-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '民國109年（下同）5月4日（週一），郵差將應送達於乙的第一審民事判決書，依法寄存於P警察 局，乙於5月21日始持通知書前往P局領取該判決書。該判決書何時發生送達效力？', '["5月4日", "5月5日", "5月14日", "5月21日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:42+00:00", "source_pdf_sha1": "48a501014870", "answer_pdf_sha1": "22372ece37e0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
